import{_ as a,o as s,c as n,ah as e}from"./chunks/framework.CZP_9SSd.js";const k=JSON.parse('{"title":"OKF 开放知识格式","description":"","frontmatter":{"title":"OKF 开放知识格式"},"headers":[],"relativePath":"ai/okf.md","filePath":"ai/okf.md","lastUpdated":1782979217000}'),d={name:"ai/okf.md"};function i(l,t,o,p,r,h){return s(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="okf-开放知识格式" tabindex="-1">OKF 开放知识格式 <a class="header-anchor" href="#okf-开放知识格式" aria-label="Permalink to &quot;OKF 开放知识格式&quot;">​</a></h1><p>OKF（Open Knowledge Format）是一种用于表示知识资产的开放格式。它使用一组普通的 Markdown 文件，加上 YAML frontmatter，描述数据、系统、指标、API、业务概念、Playbook、外部参考文档等知识对象。</p><p>官方资料：<a href="https://github.com/GoogleCloudPlatform/knowledge-catalog/tree/main/okf" target="_blank" rel="noreferrer">GoogleCloudPlatform/knowledge-catalog - okf</a></p><p>OKF 的重点不是提供新的数据库、知识图谱引擎或 RAG 平台，而是定义一种轻量、可读、可版本管理、可被人和 AI Agent 同时消费的知识文件格式。</p><p>可以把 OKF 理解为面向人类和 Agent 的 Metadata / Knowledge as Code 格式。它适合把企业里的数据目录、业务术语、表结构、指标定义、文档引用、系统依赖关系等内容组织为文件，放入 Git、文档站、Obsidian、搜索索引、RAG 系统或 Agent 上下文中使用。</p><h2 id="设计目标" tabindex="-1">设计目标 <a class="header-anchor" href="#设计目标" aria-label="Permalink to &quot;设计目标&quot;">​</a></h2><p>OKF 的主要目标包括：</p><ul><li><strong>让知识可读</strong>：普通 Markdown 文件可以直接打开阅读，不依赖专用 SDK、数据库或服务端。</li><li><strong>让知识可被 Agent 消费</strong>：Markdown 正文适合 LLM 读取，YAML frontmatter 适合机器解析、过滤、索引和路由。</li><li><strong>让知识可版本管理</strong>：Bundle 可以放在 Git 中，天然支持 diff、review、blame 和 pull request。</li><li><strong>让知识可迁移</strong>：不绑定特定厂商、模型、Agent 框架、存储系统或 UI。</li><li><strong>让知识可渐进加载</strong>：通过目录结构和 <code>index.md</code>，Agent 可以先看目录，再按需读取具体文件。</li><li><strong>让知识可以表达关系</strong>：Concept 之间通过 Markdown 链接形成图结构，而不仅是目录树。</li></ul><h2 id="不解决的问题" tabindex="-1">不解决的问题 <a class="header-anchor" href="#不解决的问题" aria-label="Permalink to &quot;不解决的问题&quot;">​</a></h2><p>OKF 的定位很轻，它不是：</p><ul><li>数据库；</li><li>向量数据库；</li><li>RAG 框架；</li><li>数据目录产品本身；</li><li>查询引擎；</li><li>固定 ontology / taxonomy；</li><li>OpenAPI、Protobuf、Avro、JSON Schema 这类领域 Schema 的替代品；</li><li>某个 Agent 框架的 Skill 格式。</li></ul><p>它更像是这些系统之间的开放中间层：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据目录 / 数据库 / API / 文档 / 业务知识</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>      OKF Bundle</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Obsidian / MkDocs / Git / Agent / RAG / 搜索索引 / 图谱可视化</span></span></code></pre></div><h2 id="核心术语" tabindex="-1">核心术语 <a class="header-anchor" href="#核心术语" aria-label="Permalink to &quot;核心术语&quot;">​</a></h2><h3 id="knowledge-bundle" tabindex="-1">Knowledge Bundle <a class="header-anchor" href="#knowledge-bundle" aria-label="Permalink to &quot;Knowledge Bundle&quot;">​</a></h3><p>Knowledge Bundle 是一个完整的 OKF 知识包，本质上是一个目录树。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my_bundle/</span></span>
<span class="line"><span>├── index.md</span></span>
<span class="line"><span>├── log.md</span></span>
<span class="line"><span>├── datasets/</span></span>
<span class="line"><span>│   ├── index.md</span></span>
<span class="line"><span>│   └── sales.md</span></span>
<span class="line"><span>├── tables/</span></span>
<span class="line"><span>│   ├── index.md</span></span>
<span class="line"><span>│   ├── orders.md</span></span>
<span class="line"><span>│   └── customers.md</span></span>
<span class="line"><span>├── metrics/</span></span>
<span class="line"><span>│   └── revenue.md</span></span>
<span class="line"><span>└── playbooks/</span></span>
<span class="line"><span>    └── freshness-alert.md</span></span></code></pre></div><p>Bundle 是 OKF 的分发单位，可以是 Git 仓库、压缩包、大仓库中的子目录，或挂载到文件系统中的目录。实践中推荐使用 Git，因为可以获得版本历史、审查和变更追踪能力。</p><h3 id="concept" tabindex="-1">Concept <a class="header-anchor" href="#concept" aria-label="Permalink to &quot;Concept&quot;">​</a></h3><p>Concept 是 OKF 中的最小知识单元，对应一个 Markdown 文件。Concept 可以表示数据库表、数据集、API Endpoint、业务指标、业务流程、故障处理 Playbook、外部参考文档或抽象业务概念。</p><h3 id="concept-id" tabindex="-1">Concept ID <a class="header-anchor" href="#concept-id" aria-label="Permalink to &quot;Concept ID&quot;">​</a></h3><p>Concept ID 是 Concept 文件在 Bundle 内的路径，去掉 <code>.md</code> 后缀。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tables/orders.md</span></span></code></pre></div><p>对应的 Concept ID 是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tables/orders</span></span></code></pre></div><h3 id="frontmatter" tabindex="-1">Frontmatter <a class="header-anchor" href="#frontmatter" aria-label="Permalink to &quot;Frontmatter&quot;">​</a></h3><p>Frontmatter 是 Markdown 文件开头的 YAML 元数据块，用 <code>---</code> 包裹。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BigQuery Table</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Orders</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">One row per completed customer order.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://console.cloud.google.com/bigquery?p=acme&amp;d=sales&amp;t=orders</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sales</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">orders</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">timestamp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-05-28T00:00:00Z</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><h3 id="body" tabindex="-1">Body <a class="header-anchor" href="#body" aria-label="Permalink to &quot;Body&quot;">​</a></h3><p>Body 是 frontmatter 后面的 Markdown 正文，用来放详细说明、Schema、示例、SQL、引用、业务规则等内容。</p><h2 id="bundle-目录结构" tabindex="-1">Bundle 目录结构 <a class="header-anchor" href="#bundle-目录结构" aria-label="Permalink to &quot;Bundle 目录结构&quot;">​</a></h2><p>一个 OKF Bundle 是一个 Markdown 目录树：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>path/to/bundle/</span></span>
<span class="line"><span>├── index.md                      # 可选：当前目录索引</span></span>
<span class="line"><span>├── log.md                        # 可选：当前目录变更日志</span></span>
<span class="line"><span>├── &lt;concept&gt;.md                  # Concept 文件</span></span>
<span class="line"><span>└── &lt;subdirectory&gt;/</span></span>
<span class="line"><span>    ├── index.md</span></span>
<span class="line"><span>    ├── &lt;concept&gt;.md</span></span>
<span class="line"><span>    └── ...</span></span></code></pre></div><p>OKF 中有两个保留文件名：</p><table tabindex="0"><thead><tr><th>文件名</th><th>作用</th></tr></thead><tbody><tr><td><code>index.md</code></td><td>当前目录的索引文件，用于渐进式浏览</td></tr><tr><td><code>log.md</code></td><td>当前目录范围内的更新日志</td></tr></tbody></table><p>除了这两个保留文件，其他 <code>.md</code> 文件都被视为 Concept 文件。</p><h2 id="concept-文件标准" tabindex="-1">Concept 文件标准 <a class="header-anchor" href="#concept-文件标准" aria-label="Permalink to &quot;Concept 文件标准&quot;">​</a></h2><p>每个 Concept 文件必须是 UTF-8 Markdown 文件，并由两部分组成：</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">YAML frontmatter</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Markdown body</span></span></code></pre></div><p>OKF 对 Concept 的硬性要求很少，只有 <code>type</code> 是必填字段。</p><table tabindex="0"><thead><tr><th>字段</th><th>是否必填</th><th>说明</th></tr></thead><tbody><tr><td><code>type</code></td><td>是</td><td>Concept 类型，例如 <code>BigQuery Table</code>、<code>Metric</code>、<code>API Endpoint</code>、<code>Playbook</code></td></tr></tbody></table><p><code>type</code> 没有中央注册表。生产者可以自行定义类型，消费者遇到未知类型时应该宽容处理，通常把它当作通用 Concept。</p><p>推荐字段如下：</p><table tabindex="0"><thead><tr><th>字段</th><th>是否必填</th><th>说明</th></tr></thead><tbody><tr><td><code>title</code></td><td>否，推荐</td><td>人类可读标题</td></tr><tr><td><code>description</code></td><td>否，推荐</td><td>一句话摘要，可用于索引、搜索结果、预览</td></tr><tr><td><code>resource</code></td><td>否，推荐</td><td>该 Concept 对应底层资源的规范 URI</td></tr><tr><td><code>tags</code></td><td>否</td><td>标签列表，用于跨目录分类</td></tr><tr><td><code>timestamp</code></td><td>否</td><td>最后一次有意义变更的 ISO 8601 时间</td></tr><tr><td>其他字段</td><td>否</td><td>生产者自定义扩展字段</td></tr></tbody></table><p>消费者不应该因为未知字段而拒绝读取文档，并且在 round-trip 时最好保留这些字段。</p><h2 id="合规性" tabindex="-1">合规性 <a class="header-anchor" href="#合规性" aria-label="Permalink to &quot;合规性&quot;">​</a></h2><p>一个 Bundle 符合 OKF v0.1，只需要满足：</p><ol><li>每个非保留 <code>.md</code> 文件都有可解析的 YAML frontmatter。</li><li>每个 frontmatter 都包含非空 <code>type</code> 字段。</li><li>如果存在 <code>index.md</code> 和 <code>log.md</code>，它们遵循对应结构约定。</li></ol><p>其他约束都是软约束。消费者不应该因为缺少可选字段、出现未知 <code>type</code>、出现未知 frontmatter key、存在 broken link 或缺少 <code>index.md</code> 而拒绝读取 Bundle。</p><h2 id="与其他工具和格式对比" tabindex="-1">与其他工具和格式对比 <a class="header-anchor" href="#与其他工具和格式对比" aria-label="Permalink to &quot;与其他工具和格式对比&quot;">​</a></h2><h3 id="okf-vs-obsidian-notion" tabindex="-1">OKF vs Obsidian / Notion <a class="header-anchor" href="#okf-vs-obsidian-notion" aria-label="Permalink to &quot;OKF vs Obsidian / Notion&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>OKF</th><th>Obsidian / Notion</th></tr></thead><tbody><tr><td>核心定位</td><td>知识交换格式</td><td>知识管理工具 / UI</td></tr><tr><td>存储形态</td><td>Markdown 文件 + YAML frontmatter</td><td>Obsidian 偏 Markdown；Notion 偏平台数据库</td></tr><tr><td>是否规定最小结构</td><td>是，规定 <code>type</code>、Concept、Bundle、<code>index.md</code>、<code>log.md</code> 等</td><td>不强调跨系统互操作标准</td></tr><tr><td>是否适合 Agent</td><td>很适合，文件可直接读</td><td>Obsidian 可以；Notion 需要 API 或导出</td></tr><tr><td>是否工具绑定</td><td>不绑定</td><td>绑定具体产品体验</td></tr></tbody></table><p>OKF 更像是给 Obsidian、Notion、文档站和 Agent 共同使用的底层知识格式，而不是替代这些工具的 UI。</p><h3 id="okf-vs-rag-向量数据库" tabindex="-1">OKF vs RAG / 向量数据库 <a class="header-anchor" href="#okf-vs-rag-向量数据库" aria-label="Permalink to &quot;OKF vs RAG / 向量数据库&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>OKF</th><th>RAG / 向量数据库</th></tr></thead><tbody><tr><td>核心定位</td><td>原始知识格式 / 中间格式</td><td>检索与问答架构</td></tr><tr><td>数据形态</td><td>Markdown 文件</td><td>Chunk、embedding、metadata</td></tr><tr><td>是否直接回答问题</td><td>不负责</td><td>负责检索增强生成</td></tr><tr><td>是否需要索引</td><td>不强制</td><td>通常需要</td></tr><tr><td>优势</td><td>可读、可审查、可版本管理</td><td>语义检索、规模化问答</td></tr></tbody></table><p>OKF 不是 RAG 的替代品，而是 RAG 的上游内容格式。可以先用 OKF 管理知识，再把 OKF 文件切 chunk、生成 embedding、入向量库。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OKF Bundle</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>Chunking / Metadata extraction</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>Embedding / Search Index</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>RAG / Agent QA</span></span></code></pre></div><h3 id="okf-vs-数据目录平台" tabindex="-1">OKF vs 数据目录平台 <a class="header-anchor" href="#okf-vs-数据目录平台" aria-label="Permalink to &quot;OKF vs 数据目录平台&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>OKF</th><th>Dataplex / Unity Catalog / Collibra</th></tr></thead><tbody><tr><td>核心定位</td><td>开放文件格式</td><td>企业级数据目录 / 治理平台</td></tr><tr><td>存储方式</td><td>文件系统 / Git</td><td>服务端平台</td></tr><tr><td>访问方式</td><td>读文件即可</td><td>API / UI / 权限系统</td></tr><tr><td>治理能力</td><td>很轻</td><td>通常更强，例如权限、血缘、审计、策略</td></tr><tr><td>可移植性</td><td>高</td><td>依赖平台</td></tr><tr><td>适合场景</td><td>交换、导出、Agent 上下文、文档化</td><td>企业治理、权限、血缘、资产管理</td></tr></tbody></table><p>OKF 不替代企业数据目录，而是可以作为数据目录的导出格式、补充文档层或 Agent 可读副本。</p><h3 id="okf-vs-openapi-protobuf-avro-json-schema" tabindex="-1">OKF vs OpenAPI / Protobuf / Avro / JSON Schema <a class="header-anchor" href="#okf-vs-openapi-protobuf-avro-json-schema" aria-label="Permalink to &quot;OKF vs OpenAPI / Protobuf / Avro / JSON Schema&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>OKF</th><th>OpenAPI / Protobuf / Avro / JSON Schema</th></tr></thead><tbody><tr><td>核心定位</td><td>知识上下文描述</td><td>领域 Schema / 接口契约 / 数据结构定义</td></tr><tr><td>机器严格性</td><td>较弱，宽松</td><td>较强，通常有严格校验</td></tr><tr><td>人类说明</td><td>强，Markdown 正文</td><td>有，但不是主要目标</td></tr><tr><td>Agent 上下文</td><td>很适合</td><td>适合结构信息，但缺少业务上下文</td></tr><tr><td>是否替代</td><td>不替代</td><td>被 OKF 引用或解释</td></tr></tbody></table><p>OKF 不替代 OpenAPI、Protobuf 或 Avro。OKF 可以引用这些 Schema，并补充业务含义、使用示例、注意事项和文档引用。</p><h3 id="okf-vs-rdf-owl-知识图谱" tabindex="-1">OKF vs RDF / OWL / 知识图谱 <a class="header-anchor" href="#okf-vs-rdf-owl-知识图谱" aria-label="Permalink to &quot;OKF vs RDF / OWL / 知识图谱&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>OKF</th><th>RDF / OWL / 知识图谱</th></tr></thead><tbody><tr><td>核心定位</td><td>轻量知识文件格式</td><td>严格语义建模 / 图数据</td></tr><tr><td>关系表达</td><td>Markdown 链接 + 上下文语义</td><td>三元组、ontology、边类型</td></tr><tr><td>学习成本</td><td>低</td><td>高</td></tr><tr><td>机器推理</td><td>弱</td><td>强</td></tr><tr><td>人类可读性</td><td>高</td><td>取决于工具</td></tr><tr><td>Agent 直接读取</td><td>很方便</td><td>通常需要工具或转换</td></tr></tbody></table><p>OKF 更适合作为轻量、可读、可维护的知识文件层；RDF / OWL 更适合需要严格语义、推理和复杂图查询的场景。</p><h3 id="okf-vs-普通-markdown-文档" tabindex="-1">OKF vs 普通 Markdown 文档 <a class="header-anchor" href="#okf-vs-普通-markdown-文档" aria-label="Permalink to &quot;OKF vs 普通 Markdown 文档&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>OKF</th><th>普通 Markdown</th></tr></thead><tbody><tr><td>是否有结构规范</td><td>有最小规范</td><td>通常没有</td></tr><tr><td>是否有机器可读元数据</td><td>有 YAML frontmatter</td><td>不一定有</td></tr><tr><td>是否定义 Concept / Bundle</td><td>有</td><td>没有</td></tr><tr><td>是否适合工具互操作</td><td>更适合</td><td>取决于约定</td></tr><tr><td>是否适合 Agent 渐进读取</td><td>更适合</td><td>需要额外设计</td></tr></tbody></table><p>OKF 可以理解成带最小标准的 Markdown 知识库。它比普通 Markdown 更适合工具消费和 Agent 上下文管理。</p><h2 id="典型使用场景" tabindex="-1">典型使用场景 <a class="header-anchor" href="#典型使用场景" aria-label="Permalink to &quot;典型使用场景&quot;">​</a></h2><h3 id="数据资产目录的文件化副本" tabindex="-1">数据资产目录的文件化副本 <a class="header-anchor" href="#数据资产目录的文件化副本" aria-label="Permalink to &quot;数据资产目录的文件化副本&quot;">​</a></h3><p>可以把 BigQuery、Snowflake、Dataplex、Unity Catalog、Collibra 里的数据资产导出成 OKF：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>datasets/</span></span>
<span class="line"><span>tables/</span></span>
<span class="line"><span>columns/</span></span>
<span class="line"><span>metrics/</span></span>
<span class="line"><span>lineage/</span></span>
<span class="line"><span>playbooks/</span></span></code></pre></div><p>适合用于数据资产审查、表结构说明、指标定义管理、数据治理文档、Agent 查表和选表。</p><h3 id="agent-上下文知识库" tabindex="-1">Agent 上下文知识库 <a class="header-anchor" href="#agent-上下文知识库" aria-label="Permalink to &quot;Agent 上下文知识库&quot;">​</a></h3><p>OKF 适合作为 Agent 的文件化上下文：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>index.md</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>按需读取 tables/orders.md</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>继续追踪 links 到 metrics/revenue.md</span></span></code></pre></div><p>这种组织方式的优点是：</p><ul><li>不需要一次性加载全部知识；</li><li>Agent 可以通过 <code>index.md</code> 逐层导航；</li><li>frontmatter 可以用于过滤；</li><li>Markdown body 可以直接作为上下文。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>OKF 是一种非常轻量的开放知识格式。它的核心约定是：用 Markdown 表达知识正文，用 YAML frontmatter 表达机器可读元数据，用目录和链接组织知识关系。</p><p>对于 Agent、Codex、Claude Code、RAG 场景，OKF 最值得借鉴的是：</p><ol><li>把知识拆成小的 Concept 文件。</li><li>用 <code>index.md</code> 做渐进式导航。</li><li>用 frontmatter 做过滤、索引和路由。</li><li>用 Markdown body 保留人类和 LLM 可读的上下文。</li><li>用普通 Markdown 链接表达关系。</li></ol>`,83)])])}const b=a(d,[["render",i]]);export{k as __pageData,b as default};
